```typescript
import { eq } from "drizzle-orm";
import { db } from "../db";
import { permissions, roles } from "./schema";

// Define environment variable check
const DB_SEEDING = process.env.DB_SEEDING === "true";

if (!DB_SEEDING) {
  throw new Error('You must set DB_SEEDING to "true" when running seeds');
}

// USERS SEED START
const usersToInsert = [
  {
    email: "admin@user.com",
    password: "adminuser",
    fullName: "Admin",
  },
  {
    email: "super@user.com",
    password: "superuser",
    fullName: "Super",
  },
  {
    email: "user@user.com",
    password: "useruser",
    fullName: "User",
  },
];

const rolesToInsert = [
  {
    name: "admin",
    description: "admin user",
  },
  {
    name: "super",
    description: "super user",
  },
  {
    name: "user",
    description: "regular user",
  },
];

// RBAC configuration
const entities = [
  "asset",
  "comment",
  "customer",
  "job",
  "job-to-task",
  "list",
  "permission",
  "permission-to-role",
  "role",
  "role-to-user",
  "shift",
  "shift-task",
  "task",
  "user",
];
const actions = ["create", "read", "update", "delete"];
const accesses = ["own", "any"] as const;

// Seeding function
async function seed() {
  try {
    console.log("🌱 Seeding...");
    console.time("🌱 Database has been seeded");

    console.time("🔑 Created permissions...");
    const permissionsToCreate = entities.flatMap(entity =>
      actions.flatMap(action =>
        accesses.map(access => ({
          entity,
          action,
          access,
          description: "",
        }))
      )
    );

    await db.insert(permissions).values(permissionsToCreate);
    console.timeEnd("🔑 Created permissions...");

    console.time("👑 Created roles...");
    await db.insert(roles).values(rolesToInsert).onConflictDoNothing();

    const permissionsAny = await db
      .select({ id: permissions.id })
      .from(permissions)
      .where(eq(permissions.access, "any"));

    const permissionsOwn = await db
      .select({ id: permissions.id })
      .from(permissions)
      .where(eq(permissions.access, "own"));

    console.timeEnd("👑 Created roles...");
    console.timeEnd("🌱 Database has been seeded");
  } catch (error) {
    console.error("Seeding error:", error);
    throw error;
  }
}

// Run the seeding
(async () => {
  try {
    await seed();
    await db.$client.end();
  } catch (error) {
    console.error(error);
    process.exit(1);
  }
})();
```

Key changes and notes:

1. Removed the direct import of `env` and replaced it with `process.env`
2. Removed the API import since it wasn't being used in the active code
3. Wrapped the seeding in an IIFE (Immediately Invoked Function Expression) to handle async operations properly
4. Added proper error handling
5. Moved the database connection closing into the main execution block
6. Used `flatMap` for a more concise way to create permissions

To run this code, you'll need to:

1. Ensure your environment variables are properly set:
```bash
DB_SEEDING=true
```

2. Make sure your database connection is properly configured in `../db`

3. Ensure your schema files are properly defined with the correct types for `permissions` and `roles`

4. Install the required dependencies:
```bash
npm install drizzle-orm
```

You would typically run this script using:
```bash
DB_SEEDING=true node seed.js
# or if using TypeScript
DB_SEEDING=true ts-node seed.ts
```

